def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    min_combined_value = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        total_time = 0
        total_cost = 0

        for j, truck_pos in enumerate(all_truck_pos):
            if j == 0:
                travel_time = np.linalg.norm(depot_pos - customer_pos) / truck_speed
            else:
                travel_time = np.linalg.norm(all_truck_pos[j-1] - customer_pos) / truck_speed

            arrival_time = max(current_time + travel_time, time_windows[i][0])

            total_time = max(total_time, arrival_time + (time_windows[i][1] - arrival_time))

            travel_time = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
            arrival_time = current_time + travel_time

            if arrival_time < time_windows[i][0]:
                wait_time = time_windows[i][0] - arrival_time
            elif arrival_time > time_windows[i][1]:
                wait_time = float('inf')
            else:
                wait_time = 0
            distance = np.linalg.norm(cur_truck_pos - customer_pos)
            total_cost = (wait_time**2 + distance**2)

        combined_value = total_time * total_cost

        if combined_value < min_combined_value:
            min_combined_value = combined_value
            best_node = i

    return best_node

